SELECT content FROM Comment WHERE comment_no = #{targetId}
SELECT c.comment_no AS commentNo, c.review_no AS reviewNo, c.user_id AS userId, CASE WHEN m.status = 'WITHDRAWN' THEN '탈퇴회원' ELSE IFNULL(d.nickname, c.user_id) END AS nickname, c.content, c.img_url AS imgUrl, c.like_cnt AS likeCnt, c.parent_no AS parentNo, c.is_deleted AS isDeleted, c.del_role AS delRole, DATE_FORMAT(c.reg_date, '%Y-%m-%d %H:%i') AS regDate, (SELECT COUNT(*) FROM comment_like cl WHERE cl.comment_no = c.comment_no AND cl.user_id = #{userId}) AS isLiked FROM comment c LEFT JOIN MEMBER m ON c.user_id = m.user_id LEFT JOIN USER_DETAIL d ON c.user_id = d.user_id WHERE c.review_no = #{reviewNo} ORDER BY CASE WHEN c.parent_no IS NULL THEN c.comment_no ELSE c.parent_no END ASC, CASE WHEN c.parent_no IS NULL THEN 0 ELSE 1 END ASC, c.reg_date ASC
INSERT INTO comment ( review_no, user_id, content, img_url, reg_date, is_deleted, like_cnt, parent_no ) VALUES ( #{reviewNo}, #{userId}, #{content}, #{imgUrl}, NOW(), 0, 0, #{parentNo} )
SELECT c.comment_no AS commentNo, c.post_no AS postNo, c.user_id AS userId, CASE WHEN m.status = 'WITHDRAWN' THEN '탈퇴회원' ELSE IFNULL(d.nickname, c.user_id) END AS nickname, c.content, c.img_url AS imgUrl, c.like_cnt AS likeCnt, c.parent_no AS parentNo, c.is_deleted AS isDeleted, c.del_role AS delRole, DATE_FORMAT(c.reg_date, '%Y-%m-%d %H:%i') AS regDate, (SELECT COUNT(*) FROM comment_like cl WHERE cl.comment_no = c.comment_no AND cl.user_id = #{userId}) AS isLiked FROM comment c LEFT JOIN MEMBER m ON c.user_id = m.user_id LEFT JOIN USER_DETAIL d ON c.user_id = d.user_id WHERE c.post_no = #{postNo} ORDER BY CASE WHEN c.parent_no IS NULL THEN c.comment_no ELSE c.parent_no END ASC, CASE WHEN c.parent_no IS NULL THEN 0 ELSE 1 END ASC, c.reg_date ASC
INSERT INTO comment ( post_no, user_id, content, img_url, reg_date, is_deleted, like_cnt, parent_no ) VALUES ( #{postNo}, #{userId}, #{content}, #{imgUrl}, NOW(), 0, 0, #{parentNo} )
UPDATE Comment SET is_deleted = 1, del_role = #{sessionRole}
WHERE comment_no = #{commentNo} OR parent_no = #{commentNo}
UPDATE comment SET content = #{content} WHERE comment_no = #{commentNo} AND user_id = #{userId}
SELECT COUNT(*) FROM comment_like WHERE comment_no = #{commentNo} AND user_id = #{userId}
INSERT INTO comment_like (comment_no, user_id) VALUES (#{commentNo}, #{userId})
DELETE FROM comment_like WHERE comment_no = #{commentNo} AND user_id = #{userId}
UPDATE comment SET like_cnt = like_cnt + #{count} WHERE comment_no = #{commentNo}
